Bmob.Sms.requestSmsCode({"mobilePhoneNumber": "131xxxxxxxx"} ).then(function(obj) {
  console.log("smsId:"+obj.smsId); // }, function(err){
  console.log("发送失败:"+err);
});

返回数据:
{ "smsId": 1232222 }

