### 　　3. 存储部分

小程序只有2M的空间，个人开发要么将图片放在这小小的2M内，要么自己配置https证书的域名，再要么利用github将自己的域名免费转为https，不会玩的可以私信我，我可以再单独写一篇将自己的域名利用github穿https证书的方法，哈哈（略过）。将图片放github不用自己的域名也行，但是利用github就要忍受它的网速慢以及随时被墙的可能性。。。 现在我们来用云开发提供的存储：

![复制代码](/images/48304ba5e6.gif)

wx.chooseImage({
      count: 1,
      sizeType: \['compressed'\],
      sourceType: \['album', 'camera'\],
      success: function (res) {

        wx.showLoading({
          title: '上传中',
        })

        const filePath = res.tempFilePaths\[0\]

        // 上传图片
        const cloudPath = 'my-image' + filePath.match(/\\.\[^.\]+?$/)\[0\]
        wx.cloud.uploadFile({
          cloudPath,
          filePath,
          success: res => {
            console.log('\[上传文件\] 成功：', res)

            let fileId = res.fileID
            let cloudPath = cloudPath
            let imagePath = filePath

            console.log( fileId )
            console.log( cloudPath )
           console.log( imagePath )
          },
          fail: e => {
            console.error('\[上传文件\] 失败：', e)
            wx.showToast({
              icon: 'none',
              title: '上传失败',
            })
          },
          complete: () => {
            wx.hideLoading()
          }
        })

      },
      fail: e => {
        console.error(e)
      }
    })

